new file mode 100644
index 0000000..75d4021
--- /dev/null
+++ b/tests/integration/notification-pipeline.integration.test.ts
@@ -0,0 +1,1310 @@
+/**
+ * Integration tests for the full notification pipeline.
+ *
+ * These tests verify end-to-end notification delivery through the complete
+ * stack: EventBus → NotificationService → Adapters → Preferences → History.
+ *
+ * Unlike the unit tests in tests/services/ and tests/adapters/, these tests
+ * wire up all real components together and verify the full pipeline behavior.
+ */
+
+import { describe, it, expect, beforeEach } from 'vitest';
+
+// Events
+import { EventBus } from '../../src/events/event-bus.js';
+import type {
+  OrderCreatedEvent,
+  OrderStatusChangedEvent,
+} from '../../src/events/event-types.js';
+
+// Services
+import {
+  NotificationService,
+  resetNotificationIdCounter,
+} from '../../src/services/notification.service.js';
+import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
+import {
+  NotificationHistoryService,
+  resetNotificationLogIdCounter,
+} from '../../src/services/notification-history.service.js';
+
+// Adapters
+import { EmailAdapter, resetEmailMessageIdCounter } from '../../src/adapters/email.adapter.js';
+import { SmsAdapter, resetSmsMessageIdCounter } from '../../src/adapters/sms.adapter.js';
+import { WebhookAdapter, resetWebhookMessageIdCounter } from '../../src/adapters/webhook.adapter.js';
+
+// Repositories
+import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
+import { UserRepository } from '../../src/repositories/user.repository.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+
+// Utils
+import { Database } from '../../src/utils/database.js';
+
+// Models
+import type { User } from '../../src/models/user.js';
+import type { Order } from '../../src/models/order.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+// ─── Test Helpers ────────────────────────────────────────────────────────────
+
+function createTestUser(overrides: Partial<User> = {}): User {
+  const now = new Date();
+  return {
+    id: 'user-1',
+    name: 'Alice',
+    email: 'alice@example.com',
+    role: 'member',
+    createdAt: now,
+    updatedAt: now,
+    ...overrides,
+  };
+}
+
+function createTestOrder(overrides: Partial<Order> = {}): Order {
+  const now = new Date();
+  return {
+    id: 'order-1',
+    userId: 'user-1',
+    items: [
+      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
+      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
+    ],
+    total: 45,
+    status: 'pending',
+    createdAt: now,
+    updatedAt: now,
+    ...overrides,
+  };
+}
+
+function createOrderCreatedEvent(user: User, order: Order): OrderCreatedEvent {
+  return {
+    type: 'order:created',
+    order,
+    user,
+    timestamp: new Date(),
+  };
+}
+
+function createOrderStatusChangedEvent(
+  order: Order,
+  previousStatus: string,
+  newStatus: string,
+): OrderStatusChangedEvent {
+  return {
+    type: 'order:status-changed',
+    order,
+    previousStatus,
+    newStatus,
+    timestamp: new Date(),
+  };
+}
+
+// ─── Integration Test Suite ──────────────────────────────────────────────────
+
+describe('Notification Pipeline Integration', () => {
+  // Shared infrastructure
+  let db: Database;
+  let eventBus: EventBus;
+
+  // Repositories
+  let userRepo: UserRepository;
+  let preferencesRepo: PreferencesRepository;
+  let notificationLogRepo: NotificationLogRepository;
+
+  // Services
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+  let historyService: NotificationHistoryService;
+
+  // Adapters
+  let emailAdapter: EmailAdapter;
+  let smsAdapter: SmsAdapter;
+  let webhookAdapter: WebhookAdapter;
+
+  // Test data
+  let alice: User;
+  let order: Order;
+
+  beforeEach(() => {
+    // Reset all ID counters
+    resetNotificationIdCounter();
+    resetEmailMessageIdCounter();
+    resetSmsMessageIdCounter();
+    resetWebhookMessageIdCounter();
+    resetNotificationLogIdCounter();
+    resetPreferencesIdCounter();
+
+    // Fresh database
+    db = new Database();
+
+    // Repositories
+    userRepo = new UserRepository(db);
+    preferencesRepo = new PreferencesRepository(db);
+    notificationLogRepo = new NotificationLogRepository(db);
+
+    // Event bus
+    eventBus = new EventBus();
+
+    // Services
+    notificationService = new NotificationService(eventBus);
+    preferencesService = new PreferencesService(preferencesRepo, userRepo);
+    historyService = new NotificationHistoryService(notificationLogRepo);
+
+    // Wire up the pipeline
+    notificationService.setPreferencesService(preferencesService);
+    notificationService.setHistoryService(historyService);
+
+    // Adapters
+    emailAdapter = new EmailAdapter();
+    smsAdapter = new SmsAdapter();
+    webhookAdapter = new WebhookAdapter();
+
+    notificationService.registerAdapter(emailAdapter);
+    notificationService.registerAdapter(smsAdapter);
+    notificationService.registerAdapter(webhookAdapter);
+
+    // Create test user in the repository (needed for preferences)
+    alice = createTestUser();
+    userRepo.save(alice);
+
+    // Create test order
+    order = createTestOrder();
+  });
+
+  // ─── Email Channel Tests ─────────────────────────────────────────────────
+
+  describe('Email channel — end-to-end', () => {
+    it('should deliver email notification when email preferences are enabled', async () => {
+      // Set up preferences with email enabled (the default)
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      // Emit order created event
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Verify email adapter received the notification
+      const sentEmails = emailAdapter.getSentEmails();
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0]!.to).toBe('alice@example.com');
+      expect(sentEmails[0]!.subject).toContain('Order Confirmation');
+      expect(sentEmails[0]!.body).toContain('Widget x2');
+      expect(sentEmails[0]!.body).toContain('Gadget x1');
+      expect(sentEmails[0]!.body).toContain('$45.00');
+
+      // Verify the email was rendered with the order-confirmation template
+      expect(sentEmails[0]!.template).toBe('order-confirmation');
+      expect(sentEmails[0]!.html).toContain('Order Confirmation');
+
+      // Verify notification was stored in service
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]!.status).toBe('sent');
+      expect(notifications[0]!.type).toBe('email');
+      expect(notifications[0]!.messageId).toBe('email-0001');
+    });
+
+    it('should not deliver email when email channel is disabled', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: { enabled: false },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // No emails should be sent
+      expect(emailAdapter.getSentEmails()).toHaveLength(0);
+
+      // No notifications stored (none were dispatched)
+      expect(notificationService.getNotifications()).toHaveLength(0);
+    });
+
+    it('should not deliver email when category is not subscribed', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['account_activity'], // Not subscribed to order_updates
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(emailAdapter.getSentEmails()).toHaveLength(0);
+      expect(notificationService.getNotifications()).toHaveLength(0);
+    });
+
+    it('should not deliver email when frequency is not immediate', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'daily_digest',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(emailAdapter.getSentEmails()).toHaveLength(0);
+    });
+  });
+
+  // ─── SMS Channel Tests ───────────────────────────────────────────────────
+
+  describe('SMS channel — end-to-end', () => {
+    it('should deliver SMS notification when SMS preferences are enabled', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Verify SMS adapter received the notification
+      const sentMessages = smsAdapter.getSentMessages();
+      expect(sentMessages).toHaveLength(1);
+      expect(sentMessages[0]!.to).toBe('+14155551234');
+      expect(sentMessages[0]!.subject).toContain('Order Confirmation');
+
+      // Verify the message was formatted for SMS (truncated to 160 chars)
+      expect(sentMessages[0]!.message.length).toBeLessThanOrEqual(160);
+
+      // Verify notification was stored
+      const notifications = notificationService.getNotifications();
+      const smsNotifications = notifications.filter((n) => n.type === 'sms');
+      expect(smsNotifications).toHaveLength(1);
+      expect(smsNotifications[0]!.status).toBe('sent');
+      expect(smsNotifications[0]!.recipient).toBe('+14155551234');
+    });
+
+    it('should not deliver SMS when SMS channel is disabled', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        sms: { enabled: false, phoneNumber: '+14155551234' },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should not deliver SMS when no phone number is configured', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        sms: { enabled: true, phoneNumber: '' },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // SMS should not be sent because shouldSendSms returns false with empty phone number
+      // AND the service checks for a non-empty phone number before dispatching
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should not deliver SMS by default (opt-in)', async () => {
+      // Create preferences with all defaults — SMS is disabled by default
+      await preferencesService.createPreferences({
+        userId: alice.id,
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+    });
+  });
+
+  // ─── Webhook Channel Tests ───────────────────────────────────────────────
+
+  describe('Webhook channel — end-to-end', () => {
+    it('should deliver webhook notification when webhook preferences are enabled', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Verify webhook adapter received the notification
+      const sentWebhooks = webhookAdapter.getSentWebhooks();
+      expect(sentWebhooks).toHaveLength(1);
+      expect(sentWebhooks[0]!.url).toBe('https://hooks.example.com/notifications');
+      expect(sentWebhooks[0]!.payload.subject).toContain('Order Confirmation');
+      expect(sentWebhooks[0]!.payload.event).toBe('notification');
+      expect(sentWebhooks[0]!.payload.priority).toBe('normal');
+      expect(sentWebhooks[0]!.statusCode).toBe(200);
+
+      // Verify notification stored
+      const notifications = notificationService.getNotifications();
+      const webhookNotifications = notifications.filter((n) => n.type === 'webhook');
+      expect(webhookNotifications).toHaveLength(1);
+      expect(webhookNotifications[0]!.status).toBe('sent');
+    });
+
+    it('should not deliver webhook when webhook channel is disabled', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        webhook: { enabled: false, url: 'https://hooks.example.com/notifications' },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
+    });
+
+    it('should not deliver webhook when no URL is configured', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        webhook: { enabled: true, url: '' },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
+    });
+
+    it('should not deliver webhook by default (opt-in)', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
+    });
+  });
+
+  // ─── Multi-Channel Tests ─────────────────────────────────────────────────
+
+  describe('Multi-channel delivery', () => {
+    it('should deliver to all enabled channels simultaneously', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // All three adapters should have received notifications
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+      expect(smsAdapter.getSentMessages()).toHaveLength(1);
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
+
+      // All three should be stored in notification service
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(3);
+
+      // All should be successful
+      expect(notifications.every((n) => n.status === 'sent')).toBe(true);
+
+      // Verify each channel's notification content is consistent
+      const emailNotif = notifications.find((n) => n.type === 'email')!;
+      const smsNotif = notifications.find((n) => n.type === 'sms')!;
+      const webhookNotif = notifications.find((n) => n.type === 'webhook')!;
+
+      // All share the same subject
+      expect(emailNotif.subject).toBe(smsNotif.subject);
+      expect(emailNotif.subject).toBe(webhookNotif.subject);
+
+      // Recipients are channel-appropriate
+      expect(emailNotif.recipient).toBe('alice@example.com');
+      expect(smsNotif.recipient).toBe('+14155551234');
+      expect(webhookNotif.recipient).toBe('https://hooks.example.com/notifications');
+    });
+
+    it('should only deliver to enabled channels (mixed preferences)', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: false,
+          phoneNumber: '+14155551234',
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Email and webhook should be sent, but not SMS
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
+
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(2);
+      expect(notifications.map((n) => n.type).sort()).toEqual(['email', 'webhook']);
+    });
+
+    it('should handle one channel failing without affecting others', async () => {
+      // Replace email adapter with one that fails
+      const failingEmailAdapter = {
+        type: 'email' as const,
+        async send() {
+          return {
+            success: false,
+            error: 'SMTP connection refused',
+            timestamp: new Date(),
+          };
+        },
+      };
+      notificationService.registerAdapter(failingEmailAdapter);
+
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // SMS and webhook should still succeed
+      expect(smsAdapter.getSentMessages()).toHaveLength(1);
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
+
+      // Email notification should be stored as failed
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(3);
+
+      const emailNotif = notifications.find((n) => n.type === 'email')!;
+      expect(emailNotif.status).toBe('failed');
+      expect(emailNotif.error).toBe('SMTP connection refused');
+
+      const smsNotif = notifications.find((n) => n.type === 'sms')!;
+      expect(smsNotif.status).toBe('sent');
+
+      const webhookNotif = notifications.find((n) => n.type === 'webhook')!;
+      expect(webhookNotif.status).toBe('sent');
+    });
+  });
+
+  // ─── History Logging Tests ───────────────────────────────────────────────
+
+  describe('Notification history logging', () => {
+    it('should log all dispatched notifications to history', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // All three notifications should be in history
+      const allHistory = historyService.getAllHistory();
+      expect(allHistory).toHaveLength(3);
+
+      // Verify each channel is represented
+      const channels = allHistory.map((h) => h.channel).sort();
+      expect(channels).toEqual(['email', 'sms', 'webhook']);
+
+      // All should show 'sent' status
+      expect(allHistory.every((h) => h.status === 'sent')).toBe(true);
+
+      // Each log entry should reference its notification
+      expect(allHistory[0]!.notificationId).toBe('notif-0001');
+      expect(allHistory[1]!.notificationId).toBe('notif-0002');
+      expect(allHistory[2]!.notificationId).toBe('notif-0003');
+    });
+
+    it('should log failed notifications to history', async () => {
+      const failingEmailAdapter = {
+        type: 'email' as const,
+        async send() {
+          return {
+            success: false,
+            error: 'SMTP timeout',
+            timestamp: new Date(),
+          };
+        },
+      };
+      notificationService.registerAdapter(failingEmailAdapter);
+
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      const allHistory = historyService.getAllHistory();
+      expect(allHistory).toHaveLength(1);
+      expect(allHistory[0]!.status).toBe('failed');
+      expect(allHistory[0]!.error).toBe('SMTP timeout');
+      expect(allHistory[0]!.channel).toBe('email');
+    });
+
+    it('should support querying history by channel', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      const emailHistory = historyService.getHistoryByChannel('email');
+      expect(emailHistory).toHaveLength(1);
+      expect(emailHistory[0]!.channel).toBe('email');
+
+      const smsHistory = historyService.getHistoryByChannel('sms');
+      expect(smsHistory).toHaveLength(1);
+      expect(smsHistory[0]!.channel).toBe('sms');
+
+      const webhookHistory = historyService.getHistoryByChannel('webhook');
+      expect(webhookHistory).toHaveLength(0);
+    });
+
+    it('should support querying history by recipient', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      const emailHistory = historyService.getHistoryByRecipient('alice@example.com');
+      expect(emailHistory).toHaveLength(1);
+
+      const smsHistory = historyService.getHistoryByRecipient('+14155551234');
+      expect(smsHistory).toHaveLength(1);
+    });
+
+    it('should support querying history by status', async () => {
+      const failingEmailAdapter = {
+        type: 'email' as const,
+        async send() {
+          return {
+            success: false,
+            error: 'Delivery failed',
+            timestamp: new Date(),
+          };
+        },
+      };
+      notificationService.registerAdapter(failingEmailAdapter);
+
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      const sentHistory = historyService.getHistoryByStatus('sent');
+      expect(sentHistory).toHaveLength(1);
+      expect(sentHistory[0]!.channel).toBe('sms');
+
+      const failedHistory = historyService.getHistoryByStatus('failed');
+      expect(failedHistory).toHaveLength(1);
+      expect(failedHistory[0]!.channel).toBe('email');
+    });
+
+    it('should support composite history queries', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Query: sent emails
+      const sentEmails = historyService.queryHistory({
+        channel: 'email',
+        status: 'sent',
+      });
+      expect(sentEmails).toHaveLength(1);
+      expect(sentEmails[0]!.recipient).toBe('alice@example.com');
+
+      // Query: sent SMS
+      const sentSms = historyService.queryHistory({
+        channel: 'sms',
+        status: 'sent',
+      });
+      expect(sentSms).toHaveLength(1);
+      expect(sentSms[0]!.recipient).toBe('+14155551234');
+    });
+
+    it('should support paginated history queries', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      // Emit events that generate multiple notifications
+      await eventBus.emit(createOrderCreatedEvent(alice, order));
+      await eventBus.emit(createOrderStatusChangedEvent(
+        { ...order, status: 'confirmed' },
+        'pending',
+        'confirmed',
+      ));
+
+      // Should have 6 history entries (3 channels × 2 events)
+      // Note: order:status-changed uses userId as email recipient,
+      // which won't match a valid email, but will still go through the pipeline
+      const totalHistory = historyService.getAllHistory();
+      expect(totalHistory.length).toBeGreaterThanOrEqual(3);
+
+      // Paginate with page size of 2
+      const page1 = historyService.queryHistoryPaginated({}, 1, 2);
+      expect(page1.items).toHaveLength(2);
+      expect(page1.page).toBe(1);
+      expect(page1.pageSize).toBe(2);
+      expect(page1.hasNext).toBe(true);
+      expect(page1.hasPrevious).toBe(false);
+    });
+  });
+
+  // ─── Preferences Respect Tests ───────────────────────────────────────────
+
+  describe('User preferences are respected', () => {
+    it('should use default preferences when none are saved (email enabled, SMS/webhook disabled)', async () => {
+      // Do NOT create preferences — defaults should apply
+      // Default: email enabled, SMS disabled, webhook disabled
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Only email should be sent (default behavior)
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
+
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]!.type).toBe('email');
+    });
+
+    it('should respect updated preferences', async () => {
+      // Start with all channels enabled
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      // Emit first event — both email and SMS
+      await eventBus.emit(createOrderCreatedEvent(alice, order));
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+      expect(smsAdapter.getSentMessages()).toHaveLength(1);
+
+      // Disable email
+      await preferencesService.updatePreferences(alice.id, {
+        email: { enabled: false },
+      });
+
+      // Emit second event — only SMS should be sent
+      await eventBus.emit(createOrderCreatedEvent(
+        alice,
+        createTestOrder({ id: 'order-2' }),
+      ));
+
+      expect(emailAdapter.getSentEmails()).toHaveLength(1); // Still 1 from before
+      expect(smsAdapter.getSentMessages()).toHaveLength(2); // Now 2
+    });
+
+    it('should stop all notifications when all channels disabled', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: { enabled: false },
+        sms: { enabled: false },
+        webhook: { enabled: false },
+      });
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      expect(emailAdapter.getSentEmails()).toHaveLength(0);
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
+      expect(notificationService.getNotifications()).toHaveLength(0);
+    });
+
+    it('should filter by notification category per channel', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates', 'marketing'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['account_activity'], // Not subscribed to order_updates via SMS
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      // Order event is category 'order_updates'
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Email: subscribed to order_updates → sent
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+
+      // SMS: NOT subscribed to order_updates → not sent
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+
+      // Webhook: subscribed to order_updates → sent
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
+    });
+  });
+
+  // ─── Order Status Changed Tests ──────────────────────────────────────────
+
+  describe('Order status changed — full pipeline', () => {
+    it('should deliver status change notifications through all enabled channels', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const updatedOrder = { ...order, status: 'confirmed' as const };
+      const event = createOrderStatusChangedEvent(updatedOrder, 'pending', 'confirmed');
+      await eventBus.emit(event);
+
+      // SMS and webhook should be delivered
+      expect(smsAdapter.getSentMessages()).toHaveLength(1);
+      expect(smsAdapter.getSentMessages()[0]!.subject).toContain('Order Update');
+
+      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
+      expect(webhookAdapter.getSentWebhooks()[0]!.payload.body).toContain('pending');
+      expect(webhookAdapter.getSentWebhooks()[0]!.payload.body).toContain('confirmed');
+
+      // Note: email for status-changed uses order.userId as recipient, not email address.
+      // This is a known design choice in the notification service.
+      // The notification should still be stored (whether it succeeds depends on if
+      // the userId looks like a valid email to the adapter).
+      const notifications = notificationService.getNotifications();
+      expect(notifications.length).toBeGreaterThanOrEqual(2);
+
+      // Verify history logged
+      const allHistory = historyService.getAllHistory();
+      expect(allHistory.length).toBeGreaterThanOrEqual(2);
+    });
+
+    it('should include status transition details in all channels', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+        webhook: {
+          enabled: true,
+          url: 'https://hooks.example.com/notifications',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const updatedOrder = { ...order, status: 'shipped' as const };
+      const event = createOrderStatusChangedEvent(updatedOrder, 'confirmed', 'shipped');
+      await eventBus.emit(event);
+
+      // SMS message should contain status transition
+      const smsMessages = smsAdapter.getSentMessages();
+      expect(smsMessages).toHaveLength(1);
+      expect(smsMessages[0]!.body).toContain('confirmed');
+      expect(smsMessages[0]!.body).toContain('shipped');
+
+      // Webhook payload should contain status transition
+      const webhooks = webhookAdapter.getSentWebhooks();
+      expect(webhooks).toHaveLength(1);
+      expect(webhooks[0]!.payload.body).toContain('confirmed');
+      expect(webhooks[0]!.payload.body).toContain('shipped');
+    });
+  });
+
+  // ─── Notification Ordering Tests ─────────────────────────────────────────
+
+  describe('Notification ordering across events', () => {
+    it('should maintain notification order for same user across events', async () => {
+      const deliveryOrder: string[] = [];
+
+      // Use a slow adapter that tracks delivery order
+      const trackingAdapter = {
+        type: 'email' as const,
+        async send(payload: NotificationPayload) {
+          if (payload.subject.includes('Confirmation')) {
+            await new Promise((resolve) => setTimeout(resolve, 30));
+          }
+          deliveryOrder.push(payload.subject);
+          return { success: true, messageId: `track-${deliveryOrder.length}`, timestamp: new Date() };
+        },
+      };
+      notificationService.registerAdapter(trackingAdapter);
+
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      // Emit order:created then order:status-changed concurrently
+      const createdEvent = createOrderCreatedEvent(alice, order);
+      const statusEvent = createOrderStatusChangedEvent(
+        { ...order, status: 'confirmed' as const },
+        'pending',
+        'confirmed',
+      );
+
+      const p1 = eventBus.emit(createdEvent);
+      const p2 = eventBus.emit(statusEvent);
+      await Promise.all([p1, p2]);
+
+      // Order confirmation should arrive before status update
+      // thanks to per-user queuing, even though the confirmation is slower
+      expect(deliveryOrder.length).toBeGreaterThanOrEqual(2);
+      expect(deliveryOrder[0]).toContain('Order Confirmation');
+      expect(deliveryOrder[1]).toContain('Order Update');
+    });
+
+    it('should not block notifications for different users', async () => {
+      const bob = createTestUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });
+      userRepo.save(bob);
+
+      const deliveryOrder: string[] = [];
+
+      const trackingAdapter = {
+        type: 'email' as const,
+        async send(payload: NotificationPayload) {
+          if (payload.recipient === 'alice@example.com') {
+            await new Promise((resolve) => setTimeout(resolve, 50));
+          }
+          deliveryOrder.push(`${payload.recipient}:${payload.subject}`);
+          return { success: true, messageId: `track-${deliveryOrder.length}`, timestamp: new Date() };
+        },
+      };
+      notificationService.registerAdapter(trackingAdapter);
+
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+      await preferencesService.createPreferences({
+        userId: bob.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      const aliceEvent = createOrderCreatedEvent(alice, order);
+      const bobOrder = createTestOrder({ id: 'order-2', userId: bob.id });
+      const bobEvent = createOrderCreatedEvent(bob, bobOrder);
+
+      // Emit concurrently — Alice's adapter is slow, Bob's is fast
+      const p1 = eventBus.emit(aliceEvent);
+      const p2 = eventBus.emit(bobEvent);
+      await Promise.all([p1, p2]);
+
+      // Bob's notification should arrive before Alice's since they're independent
+      expect(deliveryOrder).toHaveLength(2);
+      expect(deliveryOrder[0]).toContain('bob@example.com');
+      expect(deliveryOrder[1]).toContain('alice@example.com');
+    });
+
+    it('should maintain order across multi-channel notifications for the same user', async () => {
+      await preferencesService.createPreferences({
+        userId: alice.id,
+        email: {
+          enabled: true,
+          frequency: 'immediate',
+          subscribedCategories: ['order_updates'],
+        },
+        sms: {
+          enabled: true,
+          phoneNumber: '+14155551234',
+          subscribedCategories: ['order_updates'],
+        },
+      });
+
+      // Emit two events for the same user
+      await eventBus.emit(createOrderCreatedEvent(alice, order));
+      await eventBus.emit(createOrderStatusChangedEvent(
+        { ...order, status: 'confirmed' as const },
+        'pending',
+        'confirmed',
+      ));
+
+      const notifications = notificationService.getNotifications();
+
+      // Order created notifications should come before status changed notifications
+      // Find the indexes of each set
+      const orderCreatedNotifs = notifications.filter((n) =>
+        n.subject.includes('Order Confirmation'),
