+
+  // ─── Without Preferences Service (Backward Compatibility) ────────────────
+
+  describe('Backward compatibility — without preferences service', () => {
+    it('should send email-only when no preferences service is configured', async () => {
+      // Remove preferences service
+      notificationService.setPreferencesService(null);
+
+      const event = createOrderCreatedEvent(alice, order);
+      await eventBus.emit(event);
+
+      // Email should be sent (backward compatible behavior)
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+
