+      await eventBus.emit(createOrderCreatedEvent(alice, order));
+
+      // Step 2: Order confirmed
+      await eventBus.emit(createOrderStatusChangedEvent(
+        { ...order, status: 'confirmed' as const },
+        'pending',
+        'confirmed',
+      ));
+
+      // Step 3: Order shipped
+      await eventBus.emit(createOrderStatusChangedEvent(
+        { ...order, status: 'shipped' as const },
+        'confirmed',
+        'shipped',
+      ));
+
+      // Step 4: Order delivered
+      await eventBus.emit(createOrderStatusChangedEvent(
+        { ...order, status: 'delivered' as const },
+        'shipped',
+        'delivered',
+      ));
