      // Webhook payload should contain status transition
      const webhooks = webhookAdapter.getSentWebhooks();
      expect(webhooks).toHaveLength(1);
      expect(webhooks[0]!.payload.body).toContain('confirmed');
      expect(webhooks[0]!.payload.body).toContain('shipped');
