  // ─── End-to-End Scenario Tests ───────────────────────────────────────────

  describe('End-to-end scenarios', () => {
    it('should handle complete order lifecycle notifications', async () => {
      await preferencesService.createPreferences({
        userId: alice.id,
        email: {
          enabled: true,
          frequency: 'immediate',
          subscribedCategories: ['order_updates'],
        },
        sms: {
          enabled: true,
          phoneNumber: '+14155551234',
          subscribedCategories: ['order_updates'],
        },
      });

      // Step 1: Order created
      await eventBus.emit(createOrderCreatedEvent(alice, order));

      // Step 2: Order confirmed
      await eventBus.emit(createOrderStatusChangedEvent(
        { ...order, status: 'confirmed' as const },
        'pending',
        'confirmed',
      ));

      // Step 3: Order shipped
      await eventBus.emit(createOrderStatusChangedEvent(
        { ...order, status: 'shipped' as const },
        'confirmed',
        'shipped',
      ));

      // Step 4: Order delivered
      await eventBus.emit(createOrderStatusChangedEvent(
        { ...order, status: 'delivered' as const },
        'shipped',
        'delivered',
      ));

      // Verify SMS notifications for all lifecycle events
      const smsMessages = smsAdapter.getSentMessages();
      expect(smsMessages).toHaveLength(4); // 1 created + 3 status changes
      expect(smsMessages[0]!.subject).toContain('Order Confirmation');
      expect(smsMessages[1]!.subject).toContain('Order Update');
      expect(smsMessages[2]!.subject).toContain('Order Update');
      expect(smsMessages[3]!.subject).toContain('Order Update');

      // Verify history has all notifications
      const allHistory = historyService.getAllHistory();
      // At minimum: 4 SMS + some email notifications (email might fail for status-changed
      // since it uses userId as recipient)
      expect(allHistory.length).toBeGreaterThanOrEqual(4);

      // All SMS should be logged as sent
      const smsHistory = historyService.getHistoryByChannel('sms');
      expect(smsHistory).toHaveLength(4);
      expect(smsHistory.every((h) => h.status === 'sent')).toBe(true);
    });

    it('should handle multiple users with different preferences', async () => {
      const bob = createTestUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });
      userRepo.save(bob);

      // Alice: email + SMS
      await preferencesService.createPreferences({
        userId: alice.id,
        email: {
          enabled: true,
          frequency: 'immediate',
          subscribedCategories: ['order_updates'],
        },
        sms: {
          enabled: true,
          phoneNumber: '+14155551234',
          subscribedCategories: ['order_updates'],
        },
      });

      // Bob: webhook only
      await preferencesService.createPreferences({
        userId: bob.id,
        email: { enabled: false },
        webhook: {
          enabled: true,
          url: 'https://bob-hooks.example.com/notifications',
          subscribedCategories: ['order_updates'],
        },
      });

      // Alice's order
      await eventBus.emit(createOrderCreatedEvent(alice, order));

      // Bob's order
      const bobOrder = createTestOrder({ id: 'order-2', userId: bob.id });
      await eventBus.emit(createOrderCreatedEvent(bob, bobOrder));

      // Alice should get email + SMS
      const aliceEmails = emailAdapter.getSentEmailsTo('alice@example.com');
      expect(aliceEmails).toHaveLength(1);
      const aliceSms = smsAdapter.getSentMessagesTo('+14155551234');
      expect(aliceSms).toHaveLength(1);

      // Bob should get webhook only (no email, no SMS)
      const bobEmails = emailAdapter.getSentEmailsTo('bob@example.com');
      expect(bobEmails).toHaveLength(0);
      const bobWebhooks = webhookAdapter.getSentWebhooksTo('https://bob-hooks.example.com/notifications');
      expect(bobWebhooks).toHaveLength(1);

      // Verify history has all 3 notifications
      const allHistory = historyService.getAllHistory();
      expect(allHistory).toHaveLength(3);
    });

    it('should handle direct dispatchNotification with history logging', async () => {
      // Directly dispatch a notification (bypasses event handlers)
      const notification = await notificationService.dispatchNotification({
        type: 'email',
        recipient: 'direct@example.com',
        subject: 'Direct Notification',
        body: 'This was dispatched directly.',
        priority: 'high',
      });

      expect(notification.status).toBe('sent');
      expect(notification.priority).toBe('high');
      expect(notification.messageId).toBeDefined();

      // Should be in history
      const allHistory = historyService.getAllHistory();
      expect(allHistory).toHaveLength(1);
      expect(allHistory[0]!.recipient).toBe('direct@example.com');
      expect(allHistory[0]!.priority).toBe('high');
      expect(allHistory[0]!.status).toBe('sent');
    });
  });
